// src/services/experiences.js
import api from './api';
const API_URL = 'http://localhost:8000/api/experiences/';
export const experiencesService = {

  // ── Listing ────────────────────────────────────────────────────────────────
  getAll: (params = {}) =>
    api.get('/payments/experiences/', { params }),

  getById: (id) =>
    api.get(`/payments/experiences/${id}/`),

  getByCourse: (courseId) =>
    api.get('/payments/experiences/', { params: { 'section__course': courseId } }),

  // ── Purchase ───────────────────────────────────────────────────────────────
  buy: (experienceId) =>
    api.post(`/payments/experiences/${experienceId}/buy/`),

  // ── My data ───────────────────────────────────────────────────────────────
  myPurchases: () =>
    api.get('/payments/experiences/my_purchases/'),

  myCreated: () =>
    api.get('/payments/experiences/my_created/'),

  // ── Instructor CRUD ────────────────────────────────────────────────────────
  create: (data) =>
    api.post('/payments/experiences/', data, {
      headers: { 'Content-Type': 'multipart/form-data' },
    }),

  update: (id, data) =>
    api.patch(`/payments/experiences/${id}/`, data),

  toggleStatus: (id) =>
    api.patch(`/payments/experiences/${id}/toggle_status/`),

  // ── Helper: check if purchased ─────────────────────────────────────────────
  checkPurchased: async (experienceId) => {
    try {
      const res  = await api.get('/payments/experiences/my_purchases/');
      const list = res.data.results ?? res.data;
      return list.some(p => p.experience?.id === experienceId);
    } catch {
      return false;
    }
  },
};
